import React, { useState, useEffect, createContext, useContext } from 'react';
import { BrowserRouter as Router, Routes, Route, Link, Navigate, useNavigate } from 'react-router-dom';
import './App.css';

// API Configuration
const API_BASE = 'http://localhost:3001/api';

// Create API helper
const api = {
  get: async (endpoint) => {
    const token = localStorage.getItem('token');
    const res = await fetch(`${API_BASE}${endpoint}`, {
      headers: { 'Authorization': `Bearer ${token}` }
    });
    const data = await res.json();
    return { data };
  },
  post: async (endpoint, body) => {
    const token = localStorage.getItem('token');
    const res = await fetch(`${API_BASE}${endpoint}`, {
      method: 'POST',
      headers: {
        'Content-Type': 'application/json',
        'Authorization': `Bearer ${token}`
      },
      body: JSON.stringify(body)
    });
    return { data: await res.json() };
  },
  put: async (endpoint, body) => {
    const token = localStorage.getItem('token');
    const res = await fetch(`${API_BASE}${endpoint}`, {
      method: 'PUT',
      headers: {
        'Content-Type': 'application/json',
        'Authorization': `Bearer ${token}`
      },
      body: JSON.stringify(body)
    });
    return { data: await res.json() };
  },
  delete: async (endpoint) => {
    const token = localStorage.getItem('token');
    const res = await fetch(`${API_BASE}${endpoint}`, {
      method: 'DELETE',
      headers: { 'Authorization': `Bearer ${token}` }
    });
    return { data: await res.json() };
  }
};

// Auth Context
const AuthContext = createContext(null);

const useAuth = () => useContext(AuthContext);

// Login Page
function LoginPage() {
  const [username, setUsername] = useState('');
  const [password, setPassword] = useState('');
  const [error, setError] = useState('');
  const { login } = useAuth();

  const handleSubmit = async (e) => {
    e.preventDefault();
    try {
      const res = await api.post('/auth/login', { username, password });
      if (res.data.token) {
        login(res.data.token, res.data.user);
      } else {
        setError(res.data.message || 'Login failed');
      }
    } catch (err) {
      setError('Connection error');
    }
  };

  return (
    <div className="login-page">
      <div className="login-container">
        <div className="login-header">
          <div className="login-logo">
            <svg viewBox="0 0 100 100" className="logo-icon">
              <circle cx="50" cy="50" r="45" fill="#1a365d" stroke="#2c5282" strokeWidth="2"/>
              <path d="M50 20 L50 80 M30 40 L50 20 L70 40" stroke="#fff" strokeWidth="4" fill="none" strokeLinecap="round" strokeLinejoin="round"/>
              <circle cx="50" cy="55" r="15" stroke="#2c5282" strokeWidth="2" fill="none"/>
            </svg>
          </div>
          <h1>Sanaduk Saving and Credit Cooperative Ltd.</h1>
          <p>Member Management System</p>
        </div>
        <form onSubmit={handleSubmit}>
          {error && <div className="error-message">{error}</div>}
          <input type="text" placeholder="Username" value={username} onChange={e => setUsername(e.target.value)} />
          <input type="password" placeholder="Password" value={password} onChange={e => setPassword(e.target.value)} />
          <button type="submit">Login</button>
        </form>
        <div className="login-footer">
          <p>Default: admin/admin123</p>
        </div>
      </div>
    </div>
  );
}

// Dashboard
function Dashboard() {
  const [stats, setStats] = useState({ members: 0, loans: 0, shares: 0, savings: 0 });
  const { user } = useAuth();

  useEffect(() => {
    const fetchStats = async () => {
      try {
        const [membersRes, loansRes, sharesRes, savingsRes] = await Promise.all([
          api.get('/members'),
          api.get('/loans'),
          api.get('/shares'),
          api.get('/savings')
        ]);
        setStats({
          members: membersRes.data.data?.length || 0,
          loans: loansRes.data.data?.length || 0,
          shares: sharesRes.data.data?.length || 0,
          savings: savingsRes.data.data?.length || 0
        });
      } catch (error) {
        console.error('Error fetching stats:', error);
      }
    };
    fetchStats();
  }, []);

  return (
    <div className="dashboard">
      <div className="welcome-section">
        <h1>Welcome, {user?.username || 'Admin'}</h1>
        <p>Sanaduk Saving and Credit Cooperative Ltd. - Member Management Dashboard</p>
      </div>
      <div className="stats-grid">
        <div className="stat-card">
          <h3>Total Members</h3>
          <span className="stat-number">{stats.members}</span>
        </div>
        <div className="stat-card">
          <h3>Active Loans</h3>
          <span className="stat-number">{stats.loans}</span>
        </div>
        <div className="stat-card">
          <h3>Share Holders</h3>
          <span className="stat-number">{stats.shares}</span>
        </div>
        <div className="stat-card">
          <h3>Savings Accounts</h3>
          <span className="stat-number">{stats.savings}</span>
        </div>
      </div>
      <div className="dashboard-info">
        <div className="info-card">
          <h3>About Our Cooperative</h3>
          <p>Sanaduk Saving and Credit Cooperative Ltd. is dedicated to providing financial services to our members. We offer savings accounts, loans, and share investment opportunities to help our community grow together.</p>
        </div>
      </div>
    </div>
  );
}

// Members Page
function MembersPage() {
  const [members, setMembers] = useState([]);
  const [formData, setFormData] = useState({
    member_number: '', member_name: '', citizenship_number: '', 
    contact_number: '', address: '', email: '', join_date: '',
    membership_type: 'General', status: 'Active'
  });
  const [editingId, setEditingId] = useState(null);
  const [searchTerm, setSearchTerm] = useState('');

  useEffect(() => {
    fetchMembers();
  }, []);

  const fetchMembers = async () => {
    try {
      const res = await api.get('/members');
      setMembers(res.data.data || []);
    } catch (error) {
      console.error('Error:', error);
    }
  };

  const handleSubmit = async (e) => {
    e.preventDefault();
    try {
      if (editingId) {
        await api.put(`/members/${editingId}`, formData);
      } else {
        await api.post('/members', formData);
      }
      setFormData({ member_number: '', member_name: '', citizenship_number: '', contact_number: '', address: '', email: '', join_date: '', membership_type: 'General', status: 'Active' });
      setEditingId(null);
      fetchMembers();
    } catch (error) {
      alert('Error saving member');
    }
  };

  const handleEdit = (member) => {
    setFormData(member);
    setEditingId(member.id);
  };

  const handleDelete = async (id) => {
    if (window.confirm('Are you sure you want to delete this member?')) {
      try {
        await api.delete(`/members/${id}`);
        fetchMembers();
      } catch (error) {
        alert('Error deleting member');
      }
    }
  };

  const filteredMembers = members.filter(m =>
    m.member_name?.toLowerCase().includes(searchTerm.toLowerCase()) ||
    m.member_number?.toLowerCase().includes(searchTerm.toLowerCase())
  );

  return (
    <div className="members-page">
      <header className="page-header">
        <h1>Members Management</h1>
        <p>Manage cooperative members and their details</p>
      </header>
      <div className="form-section">
        <h2>{editingId ? 'Edit Member' : 'Add New Member'}</h2>
        <form onSubmit={handleSubmit}>
          <div className="form-row">
            <input type="text" placeholder="Member Number" value={formData.member_number} onChange={e => setFormData({...formData, member_number: e.target.value})} required />
            <input type="text" placeholder="Full Name" value={formData.member_name} onChange={e => setFormData({...formData, member_name: e.target.value})} required />
          </div>
          <div className="form-row">
            <input type="text" placeholder="Citizenship Number" value={formData.citizenship_number} onChange={e => setFormData({...formData, citizenship_number: e.target.value})} />
            <input type="text" placeholder="Contact Number" value={formData.contact_number} onChange={e => setFormData({...formData, contact_number: e.target.value})} />
          </div>
          <div className="form-row">
            <input type="email" placeholder="Email" value={formData.email} onChange={e => setFormData({...formData, email: e.target.value})} />
            <input type="text" placeholder="Address" value={formData.address} onChange={e => setFormData({...formData, address: e.target.value})} />
          </div>
          <div className="form-row">
            <input type="date" value={formData.join_date} onChange={e => setFormData({...formData, join_date: e.target.value})} />
            <select value={formData.membership_type} onChange={e => setFormData({...formData, membership_type: e.target.value})}>
              <option value="General">General</option>
              <option value="Founding">Founding</option>
              <option value="Life">Life</option>
            </select>
            <select value={formData.status} onChange={e => setFormData({...formData, status: e.target.value})}>
              <option value="Active">Active</option>
              <option value="Inactive">Inactive</option>
            </select>
          </div>
          <button type="submit">{editingId ? 'Update' : 'Add'} Member</button>
          {editingId && <button type="button" onClick={() => { setEditingId(null); setFormData({ member_number: '', member_name: '', citizenship_number: '', contact_number: '', address: '', email: '', join_date: '', membership_type: 'General', status: 'Active' }) }}>Cancel</button>}
        </form>
      </div>
      <div className="filter-bar">
        <input type="text" placeholder="Search members..." value={searchTerm} onChange={e => setSearchTerm(e.target.value)} />
      </div>
      <div className="table-container">
        <table className="data-table">
          <thead>
            <tr><th>Member No.</th><th>Name</th><th>Citizenship</th><th>Contact</th><th>Type</th><th>Status</th><th>Actions</th></tr>
          </thead>
          <tbody>
            {filteredMembers.map(m => (
              <tr key={m.id}>
                <td>{m.member_number}</td>
                <td>{m.member_name}</td>
                <td>{m.citizenship_number}</td>
                <td>{m.contact_number}</td>
                <td>{m.membership_type}</td>
                <td><span className={`status-badge ${m.status?.toLowerCase()}`}>{m.status}</span></td>
                <td>
                  <button onClick={() => handleEdit(m)} className="btn-sm">Edit</button>
                  <button onClick={() => handleDelete(m.id)} className="btn-danger btn-sm">Delete</button>
                </td>
              </tr>
            ))}
          </tbody>
        </table>
      </div>
    </div>
  );
}

// Loan Page
function LoanPage() {
  const [loans, setLoans] = useState([]);
  const [members, setMembers] = useState([]);
  const [formData, setFormData] = useState({ member_id: '', loan_number: '', principal_amount: '', interest_rate: '', issue_date: '', due_date: '', status: 'Active' });
  const [editingId, setEditingId] = useState(null);
  const [searchTerm, setSearchTerm] = useState('');

  useEffect(() => {
    fetchLoans();
    fetchMembers();
  }, []);

  const fetchLoans = async () => {
    try {
      const res = await api.get('/loans');
      setLoans(res.data.data || []);
    } catch (error) { console.error('Error:', error); }
  };

  const fetchMembers = async () => {
    try {
      const res = await api.get('/members');
      setMembers(res.data.data || []);
    } catch (error) { console.error('Error:', error); }
  };

  const handleSubmit = async (e) => {
    e.preventDefault();
    try {
      if (editingId) {
        await api.put(`/loans/${editingId}`, formData);
      } else {
        await api.post('/loans', formData);
      }
      setFormData({ member_id: '', loan_number: '', principal_amount: '', interest_rate: '', issue_date: '', due_date: '', status: 'Active' });
      setEditingId(null);
      fetchLoans();
    } catch (error) { alert('Error saving loan'); }
  };

  const handleEdit = (loan) => { setFormData(loan); setEditingId(loan.id); };
  const handleDelete = async (id) => { if (window.confirm('Delete this loan?')) { await api.delete(`/loans/${id}`); fetchLoans(); } };

  const getMemberName = (id) => members.find(m => m.id == id)?.member_name || 'Unknown';

  const filteredLoans = loans.filter(l => 
    l.loan_number?.toLowerCase().includes(searchTerm.toLowerCase()) ||
    getMemberName(l.member_id).toLowerCase().includes(searchTerm.toLowerCase())
  );

  return (
    <div className="loan-page">
      <header className="page-header"><h1>Loan Management</h1><p>Track and manage member loans</p></header>
      <div className="form-section">
        <h2>{editingId ? 'Edit Loan' : 'Add New Loan'}</h2>
        <form onSubmit={handleSubmit}>
          <div className="form-row">
            <select value={formData.member_id} onChange={e => setFormData({...formData, member_id: e.target.value})} required>
              <option value="">Select Member</option>
              {members.map(m => <option key={m.id} value={m.id}>{m.member_number} - {m.member_name}</option>)}
            </select>
            <input type="text" placeholder="Loan Number" value={formData.loan_number} onChange={e => setFormData({...formData, loan_number: e.target.value})} required />
          </div>
          <div className="form-row">
            <input type="number" placeholder="Principal Amount (Rs.)" value={formData.principal_amount} onChange={e => setFormData({...formData, principal_amount: e.target.value})} required />
            <input type="number" step="0.01" placeholder="Interest Rate (%)" value={formData.interest_rate} onChange={e => setFormData({...formData, interest_rate: e.target.value})} />
          </div>
          <div className="form-row">
            <input type="date" value={formData.issue_date} onChange={e => setFormData({...formData, issue_date: e.target.value})} />
            <input type="date" value={formData.due_date} onChange={e => setFormData({...formData, due_date: e.target.value})} />
            <select value={formData.status} onChange={e => setFormData({...formData, status: e.target.value})}>
              <option value="Active">Active</option>
              <option value="Closed">Closed</option>
              <option value="Default">Default</option>
            </select>
          </div>
          <button type="submit">{editingId ? 'Update' : 'Add'} Loan</button>
          {editingId && <button type="button" onClick={() => { setEditingId(null); setFormData({ member_id: '', loan_number: '', principal_amount: '', interest_rate: '', issue_date: '', due_date: '', status: 'Active' }) }}>Cancel</button>}
        </form>
      </div>
      <div className="filter-bar"><input type="text" placeholder="Search loans..." value={searchTerm} onChange={e => setSearchTerm(e.target.value)} /></div>
      <div className="table-container">
        <table className="data-table">
          <thead><tr><th>Loan No.</th><th>Member</th><th>Principal</th><th>Rate</th><th>Issue Date</th><th>Due Date</th><th>Status</th><th>Actions</th></tr></thead>
          <tbody>
            {filteredLoans.map(l => (
              <tr key={l.id}>
                <td>{l.loan_number}</td>
                <td>{getMemberName(l.member_id)}</td>
                <td>Rs. {parseFloat(l.principal_amount || 0).toLocaleString()}</td>
                <td>{l.interest_rate}%</td>
                <td>{l.issue_date}</td>
                <td>{l.due_date}</td>
                <td><span className={`status-badge ${l.status?.toLowerCase()}`}>{l.status}</span></td>
                <td><button onClick={() => handleEdit(l)} className="btn-sm">Edit</button><button onClick={() => handleDelete(l.id)} className="btn-danger btn-sm">Delete</button></td>
              </tr>
            ))}
          </tbody>
        </table>
      </div>
    </div>
  );
}

// Share Page
function SharePage() {
  const [shares, setShares] = useState([]);
  const [members, setMembers] = useState([]);
  const [formData, setFormData] = useState({ member_id: '', share_number: '', quantity: '', purchase_date: '', price_per_share: '', status: 'Active' });
  const [editingId, setEditingId] = useState(null);
  const [searchTerm, setSearchTerm] = useState('');

  useEffect(() => { fetchShares(); fetchMembers(); }, []);

  const fetchShares = async () => { const res = await api.get('/shares'); setShares(res.data.data || []); };
  const fetchMembers = async () => { const res = await api.get('/members'); setMembers(res.data.data || []); };

  const handleSubmit = async (e) => {
    e.preventDefault();
    try {
      if (editingId) await api.put(`/shares/${editingId}`, formData);
      else await api.post('/shares', formData);
      setFormData({ member_id: '', share_number: '', quantity: '', purchase_date: '', price_per_share: '', status: 'Active' });
      setEditingId(null);
      fetchShares();
    } catch (error) { alert('Error saving share'); }
  };

  const handleEdit = (share) => { setFormData(share); setEditingId(share.id); };
  const handleDelete = async (id) => { if (window.confirm('Delete this share?')) { await api.delete(`/shares/${id}`); fetchShares(); } };
  const getMemberName = (id) => members.find(m => m.id == id)?.member_name || 'Unknown';

  const filteredShares = shares.filter(s => 
    s.share_number?.toLowerCase().includes(searchTerm.toLowerCase()) ||
    getMemberName(s.member_id).toLowerCase().includes(searchTerm.toLowerCase())
  );

  return (
    <div className="share-page">
      <header className="page-header"><h1>Share Management</h1><p>Manage member share investments</p></header>
      <div className="form-section">
        <h2>{editingId ? 'Edit Share' : 'Add New Share'}</h2>
        <form onSubmit={handleSubmit}>
          <div className="form-row">
            <select value={formData.member_id} onChange={e => setFormData({...formData, member_id: e.target.value})} required>
              <option value="">Select Member</option>
              {members.map(m => <option key={m.id} value={m.id}>{m.member_number} - {m.member_name}</option>)}
            </select>
            <input type="text" placeholder="Share Number" value={formData.share_number} onChange={e => setFormData({...formData, share_number: e.target.value})} required />
          </div>
          <div className="form-row">
            <input type="number" placeholder="Quantity" value={formData.quantity} onChange={e => setFormData({...formData, quantity: e.target.value})} required />
            <input type="number" step="0.01" placeholder="Price per Share (Rs.)" value={formData.price_per_share} onChange={e => setFormData({...formData, price_per_share: e.target.value})} />
            <input type="date" value={formData.purchase_date} onChange={e => setFormData({...formData, purchase_date: e.target.value})} />
            <select value={formData.status} onChange={e => setFormData({...formData, status: e.target.value})}>
              <option value="Active">Active</option>
              <option value="Transferred">Transferred</option>
              <option value="Redeemed">Redeemed</option>
            </select>
          </div>
          <button type="submit">{editingId ? 'Update' : 'Add'} Share</button>
          {editingId && <button type="button" onClick={() => { setEditingId(null); setFormData({ member_id: '', share_number: '', quantity: '', purchase_date: '', price_per_share: '', status: 'Active' }) }}>Cancel</button>}
        </form>
      </div>
      <div className="filter-bar"><input type="text" placeholder="Search shares..." value={searchTerm} onChange={e => setSearchTerm(e.target.value)} /></div>
      <div className="table-container">
        <table className="data-table">
          <thead><tr><th>Share No.</th><th>Member</th><th>Quantity</th><th>Price/Share</th><th>Total Value</th><th>Purchase Date</th><th>Status</th><th>Actions</th></tr></thead>
          <tbody>
            {filteredShares.map(s => {
              const total = (parseFloat(s.quantity || 0) * parseFloat(s.price_per_share || 0));
              return (
                <tr key={s.id}>
                  <td>{s.share_number}</td>
                  <td>{getMemberName(s.member_id)}</td>
                  <td>{s.quantity}</td>
                  <td>Rs. {parseFloat(s.price_per_share || 0).toLocaleString()}</td>
                  <td>Rs. {total.toLocaleString()}</td>
                  <td>{s.purchase_date}</td>
                  <td><span className={`status-badge ${s.status?.toLowerCase()}`}>{s.status}</span></td>
                  <td><button onClick={() => handleEdit(s)} className="btn-sm">Edit</button><button onClick={() => handleDelete(s.id)} className="btn-danger btn-sm">Delete</button></td>
                </tr>
              );
            })}
          </tbody>
        </table>
      </div>
    </div>
  );
}

// Savings Page
function SavingsPage() {
  const [savings, setSavings] = useState([]);
  const [members, setMembers] = useState([]);
  const [monthlyData, setMonthlyData] = useState({});
  const [selectedYear, setSelectedYear] = useState(2082);
  const [searchTerm, setSearchTerm] = useState('');

  const years = Array.from({ length: 16 }, (_, i) => 2075 + i);

  useEffect(() => {
    fetchData();
  }, [selectedYear]);

  const fetchData = async () => {
    try {
      const [savingsRes, membersRes, monthlyRes] = await Promise.all([
        api.get('/savings'),
        api.get('/members'),
        api.get('/monthly-savings/summary')
      ]);
      setSavings(savingsRes.data.data || []);
      setMembers(membersRes.data.data || []);
      
      const monthlyMap = {};
      const summaryData = monthlyRes.data.data;
      if (summaryData && summaryData.memberSummary) {
        summaryData.memberSummary.forEach(item => {
          monthlyMap[item.member_id] = {
            yearly_total: item.yearly_total,
            months_count: item.months_count
          };
        });
      }
      setMonthlyData(monthlyMap);
    } catch (error) {
      console.error('Error fetching data:', error);
    }
  };

  const getMemberName = (id) => members.find(m => m.id == id)?.member_name || 'Unknown';

  const filteredSavings = savings.filter(s => {
    const matchesSearch = 
      s.account_number?.toLowerCase().includes(searchTerm.toLowerCase()) ||
      getMemberName(s.member_id).toLowerCase().includes(searchTerm.toLowerCase());
    return matchesSearch;
  });

  return (
    <div className="savings-page">
      <header className="page-header">
        <h1>Savings Management</h1>
        <p>Member savings overview (Yearly totals from Monthly Savings)</p>
      </header>

      <div className="filter-bar">
        <select 
          value={selectedYear} 
          onChange={(e) => setSelectedYear(parseInt(e.target.value))}
          className="filter-select"
        >
          {years.map(year => (
            <option key={year} value={year}>{year} B.S.</option>
          ))}
        </select>
        <input
          type="text"
          placeholder="Search by account number or member name..."
          value={searchTerm}
          onChange={(e) => setSearchTerm(e.target.value)}
          className="search-input"
        />
      </div>

      <div className="table-container">
        <table className="data-table">
          <thead>
            <tr>
              <th>Account No.</th>
              <th>Member</th>
              <th>Yearly Total (B.S.)</th>
              <th>Months Recorded</th>
            </tr>
          </thead>
          <tbody>
            {filteredSavings.map((saving) => (
              <tr key={saving.id}>
                <td>{saving.account_number}</td>
                <td>{getMemberName(saving.member_id)}</td>
                <td>Rs. {(monthlyData[saving.member_id]?.yearly_total || 0).toLocaleString()}</td>
                <td>{monthlyData[saving.member_id]?.months_count || 0}/12</td>
              </tr>
            ))}
          </tbody>
        </table>
      </div>
    </div>
  );
}

// Monthly Savings Page
function MonthlySavingsPage() {
  const [members, setMembers] = useState([]);
  const [selectedMember, setSelectedMember] = useState('');
  const [selectedYear, setSelectedYear] = useState(2082);
  const [monthlyData, setMonthlyData] = useState({});
  const [summary, setSummary] = useState(null);
  const [loading, setLoading] = useState(false);
  const [saving, setSaving] = useState(false);

  const months = [
    { value: 1, name: 'Baisakh' },
    { value: 2, name: 'Jestha' },
    { value: 3, name: 'Ashadh' },
    { value: 4, name: 'Shrawan' },
    { value: 5, name: 'Bhadra' },
    { value: 6, name: 'Ashwin' },
    { value: 7, name: 'Kartik' },
    { value: 8, name: 'Mangsir' },
    { value: 9, name: 'Poush' },
    { value: 10, name: 'Magh' },
    { value: 11, name: 'Falgun' },
    { value: 12, name: 'Chaitra' }
  ];

  const nepaliMonths = [
    'Baisakh', 'Jestha', 'Ashadh', 'Shrawan', 'Bhadra', 'Ashwin',
    'Kartik', 'Mangsir', 'Poush', 'Magh', 'Falgun', 'Chaitra'
  ];

  const years = Array.from({ length: 16 }, (_, i) => 2075 + i);

  useEffect(() => {
    fetchMembers();
  }, []);

  useEffect(() => {
    if (selectedMember && selectedYear) {
      fetchMonthlyData();
      fetchSummary();
    }
  }, [selectedMember, selectedYear]);

  const fetchMembers = async () => {
    try {
      const { data } = await api.get('/members');
      setMembers(data.data || []);
    } catch (error) {
      console.error('Error fetching members:', error);
    }
  };

  const fetchMonthlyData = async () => {
    setLoading(true);
    try {
      const { data } = await api.get(`/monthly-savings?member_id=${selectedMember}&year=${selectedYear}`);
      const monthlyMap = {};
      (data.data || []).forEach(item => {
        monthlyMap[item.month] = item;
      });
      setMonthlyData(monthlyMap);
    } catch (error) {
      console.error('Error fetching monthly data:', error);
    }
    setLoading(false);
  };

  const fetchSummary = async () => {
    try {
      const url = selectedMember 
        ? `/monthly-savings/summary?year=${selectedYear}`
        : `/monthly-savings/summary?year=${selectedYear}`;
      const { data } = await api.get(url);
      setSummary(data.data);
    } catch (error) {
      console.error('Error fetching summary:', error);
    }
  };

  const handleSaveMonth = async (month) => {
    const amount = monthlyData[month]?.total_amount || 0;
    setSaving(true);
    try {
      await api.post('/monthly-savings', {
        member_id: selectedMember,
        year: selectedYear,
        month: month,
        month_name: nepaliMonths[month - 1],
        total_amount: amount
      });
      fetchMonthlyData();
      fetchSummary();
      alert('Monthly savings saved successfully!');
    } catch (error) {
      console.error('Error saving monthly savings:', error);
      alert('Error saving monthly savings');
    }
    setSaving(false);
  };

  const handleDeleteMonth = async (month) => {
    const entry = monthlyData[month];
    if (!entry?.id) return;
    
    if (!confirm('Are you sure you want to delete this entry?')) return;
    
    try {
      await api.delete(`/monthly-savings/${entry.id}`);
      fetchMonthlyData();
      fetchSummary();
    } catch (error) {
      console.error('Error deleting entry:', error);
      alert('Error deleting entry');
    }
  };

  const getYearlyTotal = () => {
    return Object.values(monthlyData).reduce((sum, item) => sum + (item.total_amount || 0), 0);
  };

  return (
    <div className="monthly-savings-page">
      <header className="page-header">
        <h1>Monthly Savings Management (B.S.)</h1>
        <p>Manage monthly savings for each member (Nepali Year)</p>
      </header>

      <div className="filter-bar">
        <select 
          value={selectedMember} 
          onChange={(e) => setSelectedMember(e.target.value)}
          className="filter-select"
        >
          <option value="">Select Member</option>
          {members.map(member => (
            <option key={member.id} value={member.id}>
              {member.member_number} - {member.member_name}
            </option>
          ))}
        </select>
        
        <select 
          value={selectedYear} 
          onChange={(e) => setSelectedYear(parseInt(e.target.value))}
          className="filter-select"
        >
          {years.map(year => (
            <option key={year} value={year}>{year}</option>
          ))}
        </select>
      </div>

      {selectedMember && (
        <>
          {summary && (
            <div className="summary-cards">
              <div className="summary-card">
                <h3>Yearly Total Savings</h3>
                <span className="summary-value">Rs. {(summary.grandTotal || 0).toLocaleString()}</span>
              </div>
              <div className="summary-card">
                <h3>Total This Year</h3>
                <span className="summary-value">Rs. {getYearlyTotal().toLocaleString()}</span>
              </div>
              <div className="summary-card">
                <h3>Months Recorded</h3>
                <span className="summary-value">{Object.keys(monthlyData).length}/12</span>
              </div>
            </div>
          )}

          <div className="monthly-grid">
            <h3>Monthly Savings for {selectedYear}</h3>
            <div className="months-container">
              {months.map((month) => (
                <div key={month.value} className="month-card">
                  <div className="month-header">
                    <span className="month-name">{month.name}</span>
                    <span className="month-number">{month.value}</span>
                  </div>
                  <div className="month-input">
                    <label>Amount (Rs.)</label>
                    <input
                      type="number"
                      value={monthlyData[month.value]?.total_amount || ''}
                      onChange={(e) => setMonthlyData(prev => ({
                        ...prev,
                        [month.value]: {
                          ...prev[month.value],
                          total_amount: parseFloat(e.target.value) || 0
                        }
                      }))}
                      placeholder="0"
                    />
                  </div>
                  <div className="month-actions">
                    <button 
                      className="btn-primary btn-sm"
                      onClick={() => handleSaveMonth(month.value)}
                      disabled={saving}
                    >
                      Save
                    </button>
                    {monthlyData[month.value]?.id && (
                      <button 
                        className="btn-danger btn-sm"
                        onClick={() => handleDeleteMonth(month.value)}
                      >
                        Delete
                      </button>
                    )}
                  </div>
                </div>
              ))}
            </div>
          </div>

          <div className="yearly-overview">
            <h3>Yearly Overview</h3>
            <div className="yearly-chart">
              {months.map((month) => {
                const amount = monthlyData[month.value]?.total_amount || 0;
                const maxAmount = Math.max(...Object.values(monthlyData).map(m => m.total_amount || 0), 1);
                const height = maxAmount > 0 ? (amount / maxAmount) * 100 : 0;
                
                return (
                  <div key={month.value} className="chart-bar-container">
                    <div className="chart-bar" style={{ height: `${height}%` }}></div>
                    <span className="chart-label">{month.name.substring(0, 3)}</span>
                    <span className="chart-value">Rs. {amount.toLocaleString()}</span>
                  </div>
                );
              })}
            </div>
          </div>
        </>
      )}
    </div>
  );
}

function ProfilePage() {
  const [user, setUser] = useState(null);
  const [loading, setLoading] = useState(true);
  const [isEditingName, setIsEditingName] = useState(false);
  const [editName, setEditName] = useState('');
  const [profilePhoto, setProfilePhoto] = useState(null);

  useEffect(() => {
    fetchUser();
  }, []);

  const fetchUser = async () => {
    try {
      const token = localStorage.getItem('token');
      const res = await fetch(`${API_BASE}/auth/me`, {
        headers: { 'Authorization': `Bearer ${token}` }
      });
      const data = await res.json();
      setUser(data.data);
      setEditName(data.data?.username || '');
    } catch (error) {
      console.error('Error fetching user:', error);
    }
    setLoading(false);
  };

  const handleNameSave = async () => {
    try {
      const token = localStorage.getItem('token');
      const res = await fetch(`${API_BASE}/auth/update-profile`, {
        method: 'PUT',
        headers: {
          'Content-Type': 'application/json',
          'Authorization': `Bearer ${token}`
        },
        body: JSON.stringify({ username: editName })
      });
      const data = await res.json();
      if (data.success) {
        setUser({ ...user, username: editName });
        setIsEditingName(false);
        localStorage.setItem('user', JSON.stringify({ ...user, username: editName }));
      } else {
        alert(data.message || 'Error updating name');
      }
    } catch (error) {
      console.error('Error updating name:', error);
      alert('Error updating name');
    }
  };

  const handlePhotoUpload = async (e) => {
    const file = e.target.files[0];
    if (!file) return;

    const formData = new FormData();
    formData.append('photo', file);

    try {
      const token = localStorage.getItem('token');
      const res = await fetch(`${API_BASE}/auth/upload-photo`, {
        method: 'POST',
        headers: {
          'Authorization': `Bearer ${token}`
        },
        body: formData
      });
      const data = await res.json();
      if (data.success) {
        setUser({ ...user, profile_photo: data.photoUrl });
        alert('Profile photo updated!');
      } else {
        alert(data.message || 'Error uploading photo');
      }
    } catch (error) {
      console.error('Error uploading photo:', error);
      alert('Error uploading photo');
    }
  };

  if (loading) return <div className="loading">Loading...</div>;

  return (
    <div className="profile-page">
      <header className="page-header">
        <h1>My Profile</h1>
        <p>View and manage your account</p>
      </header>
      <div className="profile-card">
        <div className="profile-header">
          <div className="profile-avatar-section">
            <div className="avatar">{
              user?.profile_photo 
                ? <img src={user.profile_photo} alt="Profile" style={{ width: '100%', height: '100%', borderRadius: '50%', objectFit: 'cover' }} />
                : user?.username?.charAt(0).toUpperCase() || 'A'
            }</div>
            <label className="avatar-upload">
              📷
              <input type="file" accept="image/*" onChange={handlePhotoUpload} />
            </label>
          </div>
          <div className="profile-info">
            {isEditingName ? (
              <>
                <div className="profile-name-input" style={{ display: 'block' }}>
                  <input 
                    type="text" 
                    value={editName} 
                    onChange={(e) => setEditName(e.target.value)}
                    placeholder="Enter your name"
                  />
                </div>
                <div style={{ display: 'flex', gap: '8px', marginTop: '12px' }}>
                  <button className="btn-primary btn-sm" onClick={handleNameSave}>Save</button>
                  <button className="name-edit-btn" onClick={() => setIsEditingName(false)}>Cancel</button>
                </div>
              </>
            ) : (
              <>
                <h2>{user?.username || 'Admin'}</h2>
                <button className="name-edit-btn" onClick={() => setIsEditingName(true)}>Edit Name</button>
              </>
            )}
            <p>{user?.role || 'Administrator'}</p>
          </div>
        </div>
        <div className="profile-details">
          <div className="detail-row">
            <span className="label">Username:</span>
            <span className="value">{user?.username}</span>
          </div>
          <div className="detail-row">
            <span className="label">Role:</span>
            <span className="value">{user?.role}</span>
          </div>
          {user?.email && (
            <div className="detail-row">
              <span className="label">Email:</span>
              <span className="value">{user.email}</span>
            </div>
          )}
          <div className="detail-row">
            <span className="label">Member Since:</span>
            <span className="value">{user?.created_at ? new Date(user.created_at).toLocaleDateString() : 'N/A'}</span>
          </div>
        </div>
      </div>
    </div>
  );
}

// Protected Route
function ProtectedRoute({ children }) {
  const { isAuthenticated } = useAuth();
  return isAuthenticated ? children : <Navigate to="/login" />;
}

// Navigation
function Navigation() {
  const { logout } = useAuth();
  
  return (
    <nav className="sidebar">
      <div className="sidebar-header">
        <div className="logo">
          <svg viewBox="0 0 100 100" className="logo-svg">
            <circle cx="50" cy="50" r="45" fill="#1a365d" stroke="#2c5282" strokeWidth="2"/>
            <path d="M50 20 L50 80 M30 40 L50 20 L70 40" stroke="#fff" strokeWidth="4" fill="none" strokeLinecap="round" strokeLinejoin="round"/>
            <circle cx="50" cy="55" r="15" stroke="#2c5282" strokeWidth="2" fill="none"/>
